  1	import * as React from 'react';
  2	import {
  3	  Button,
  4	  ButtonVariant,
  5	  Modal,
  6	  Tab,
  7	  TabProps,
  8	  Tabs,
  9	  Toolbar,
 10	  ToolbarGroup,
 11	  ToolbarItem,
 12	  Tooltip
 13	} from '@patternfly/react-core';
 14	import {
 15	  AuthorizationPolicy,
 16	  DestinationRule,
 17	  Gateway,
 18	  GroupVersionKind,
 19	  K8sGateway,
 20	  K8sGRPCRoute,
 21	  K8sHTTPRoute,
 22	  K8sReferenceGrant,
 23	  PeerAuthentication,
 24	  Sidecar,
 25	  VirtualService
 26	} from 'types/IstioObjects';
 27	import { CopyToClipboard } from 'react-copy-to-clipboard';
 28	import { kialiStyle } from 'styles/StyleUtils';
 29	import { KialiIcon } from '../../config/KialiIcon';
 30	import { yamlDumpOptions } from '../../types/IstioConfigDetails';
 31	import { EditResources } from './EditResources';
 32	import { cloneDeep } from 'lodash';
 33	import { PFColors } from '../Pf/PfColors';
 34	import _ from 'lodash';
 35	import { download } from 'utils/Common';
 36	import { t } from 'utils/I18nUtils';
 37	import { dump } from 'js-yaml';
 38	import { getGVKTypeString } from '../../utils/IstioConfigUtils';
 39	
 40	export type IstioConfigItem =
 41	  | AuthorizationPolicy
 42	  | Sidecar
 43	  | DestinationRule
 44	  | PeerAuthentication
 45	  | Gateway
 46	  | K8sGateway
 47	  | K8sGRPCRoute
 48	  | K8sHTTPRoute
 49	  | K8sReferenceGrant
 50	  | VirtualService;
 51	
 52	export interface ConfigPreviewItem {
 53	  items: IstioConfigItem[];
 54	  objectGVK: GroupVersionKind;
 55	  title: string;
 56	}
 57	
 58	interface Props {
 59	  actions?: any;
 60	  disableAction?: boolean;
 61	  downloadPrefix: string;
 62	  isOpen: boolean;
 63	  items: ConfigPreviewItem[];
 64	  ns: string;
 65	  onClose: () => void;
 66	  onConfirm: (items: ConfigPreviewItem[]) => void;
 67	  onKeyPress?: (e: any) => void;
 68	  opTarget: string;
 69	  title: string;
 70	}
 71	
 72	interface State {
 73	  copied: boolean;
 74	  items: ConfigPreviewItem[];
 75	  mainTab: string;
 76	  modalOpen: boolean;
 77	  newIstioPage: boolean;
 78	}
 79	
 80	const separator = '\n---\n\n';
 81	
 82	const downloadButtonStyle = kialiStyle({
 83	  marginLeft: '0.5rem'
 84	});
 85	
 86	const iconStyle = kialiStyle({
 87	  marginLeft: '0.25rem'
 88	});
 89	
 90	// From react-patternfly library (not exported in the library)
 91	type TabElement = React.ReactElement<TabProps, React.JSXElementConstructor<TabProps>>;
 92	type TabsChild = TabElement | boolean | null | undefined;
 93	
 94	export class IstioConfigPreview extends React.Component<Props, State> {
 95	  constructor(props: Props) {
 96	    super(props);
 97	    const newIstioPage = window.location.pathname.split('/')[2] === 'istio';
 98	
 99	    this.state = {
100	      copied: false,
101	      mainTab: this.props.items.length > 0 ? this.props.items[0].title.toLocaleLowerCase().replace(/\s/g, '') : '',
102	      newIstioPage: newIstioPage,
103	      items: cloneDeep(this.props.items),
104	      modalOpen: this.props.isOpen
105	    };
106	  }
107	
108	  componentDidUpdate(prevProps: Props): void {
109	    if (!_.isEqual(prevProps.items, this.props.items) || prevProps.isOpen !== this.props.isOpen) {
110	      this.setStateValues(this.props.items);
111	    }
112	  }
113	
114	  setStateValues = (items: ConfigPreviewItem[]): void => {
115	    this.setState({
116	      mainTab: items.length > 0 ? items[0].title.toLocaleLowerCase().replace(/\s/g, '') : '',
117	      items: cloneDeep(items),
118	      modalOpen: this.props.isOpen
119	    });
120	  };
121	
122	  getPreviewYaml = (): string => {
123	    let previewYaml = '';
124	
125	    this.state.items.forEach((obj: ConfigPreviewItem, index: number) => {
126	      previewYaml += obj.items.map(item => dump(item, yamlDumpOptions)).join(separator);
127	
128	      if (index !== this.state.items.length - 1) {
129	        previewYaml += separator;
130	      }
131	    });
132	
133	    return previewYaml;
134	  };
135	
136	  onConfirm = (): void => {
137	    this.props.onConfirm(this.state.items);
138	    this.setStateValues([]);
139	  };
140	
141	  editorChange = (object: IstioConfigItem, index: number, title: string): void => {
142	    const items = this.state.items;
143	    const ind = items.findIndex(it =>
144	      this.state.newIstioPage
145	        ? it.title === title && it.items.find(t => t.metadata.namespace === object.metadata.namespace)
146	        : it.title === title
147	    );
148	
149	    const config = items[ind];
150	    config.items[
151	      this.state.newIstioPage
152	        ? config.items.findIndex(fi => fi.metadata.namespace === object.metadata.namespace)
153	        : index
154	    ] = object;
155	
156	    items[ind] = config;
157	    this.setState({ items });
158	  };
159	
160	  addResource = (item: ConfigPreviewItem): TabsChild => {
161	    const key = item.title.toLocaleLowerCase().replace(/\s/g, '');
162	    const filterItems =
163	      this.props.items.length > 0
164	        ? (this.state.newIstioPage ? this.groupItems(this.props.items) : this.props.items).filter(
165	            it => it.title === item.title
166	          )
167	        : [];
168	
169	    const propItems = filterItems.length > 0 ? filterItems[0].items : [];
170	
171	    return (
172	      <Tab eventKey={key} key={`${key}_tab_preview`} title={item.title}>
173	        <EditResources
174	          items={
175	            this.state.newIstioPage
176	              ? item.items.sort((a, b) => a.metadata.namespace!.localeCompare(b.metadata.namespace!))
177	              : item.items
178	          }
179	          orig={
180	            (this.state.newIstioPage
181	              ? propItems.sort((a, b) => a.metadata.namespace!.localeCompare(b.metadata.namespace!))
182	              : propItems) as IstioConfigItem[]
183	          }
184	          isIstioNew={this.state.newIstioPage}
185	          onChange={(obj, index) => this.editorChange(obj, index, item.title)}
186	        />
187	      </Tab>
188	    );
189	  };
190	
191	  groupItems = (list: ConfigPreviewItem[] = this.state.items): ConfigPreviewItem[] => {
192	    const gvks = _.uniq(list.map(item => item.objectGVK));
193	
194	    const itemsGrouped: ConfigPreviewItem[] = gvks.map(gvk => {
195	      const filtered = list.filter(it => getGVKTypeString(it.objectGVK) === getGVKTypeString(gvk));
196	      const item: ConfigPreviewItem = { objectGVK: gvk, title: filtered[0].title, items: [] };
197	      filtered.map(f => item.items.push(f.items[0]));
198	      return item;
199	    });
200	
201	    return itemsGrouped;
202	  };
203	
204	  render(): React.ReactNode {
205	    return (
206	      <Modal
207	        width={'75%'}
208	        title={this.props.title}
209	        isOpen={this.state.modalOpen}
210	        onClose={this.props.onClose}
211	        onKeyDown={e => (this.props.onKeyPress ? this.props.onKeyPress(e) : {})}
212	        actions={
213	          this.props.actions
214	            ? this.props.actions
215	            : [
216	                <Button
217	                  key={this.props.opTarget}
218	                  variant={this.props.opTarget === 'delete' ? 'danger' : 'primary'}
219	                  isDisabled={this.props.disableAction}
220	                  onClick={this.onConfirm}
221	                  data-test={this.props.opTarget}
222	                >
223	                  {t(this.props.opTarget[0]?.toUpperCase() + this.props.opTarget?.substring(1))}
224	                </Button>,
225	                <Button key="cancel" variant={ButtonVariant.secondary} onClick={this.props.onClose}>
226	                  {t('Cancel')}
227	                </Button>
228	              ]
229	        }
230	      >
231	        <Toolbar>
232	          <ToolbarGroup
233	            className={kialiStyle({
234	              marginLeft: 'auto'
235	            })}
236	          >
237	            <ToolbarItem>
238	              <Tooltip
239	                content={<>{this.state.copied ? t('Copied') : t('Copy all resources')}</>}
240	                onTooltipHidden={() => this.setState({ copied: false })}
241	              >
242	                <CopyToClipboard text={this.getPreviewYaml()}>
243	                  <Button
244	                    variant={ButtonVariant.link}
245	                    aria-label={t('Copy')}
246	                    isInline
247	                    onClick={() => this.setState({ copied: true })}
248	                  >
249	                    <KialiIcon.Copy />
250	                    <span className={iconStyle}>{t('Copy')}</span>
251	                  </Button>
252	                </CopyToClipboard>
253	              </Tooltip>
254	            </ToolbarItem>
255	            <ToolbarItem>
256	              <Tooltip content={<>{t('Download all resources in a file')}</>}>
257	                <Button
258	                  variant={ButtonVariant.link}
259	                  isInline
260	                  aria-label={t('Download')}
261	                  className={downloadButtonStyle}
262	                  onClick={() => download(this.getPreviewYaml(), `${this.props.downloadPrefix}_${this.props.ns}.yaml`)}
263	                >
264	                  <KialiIcon.Download />
265	                  <span className={iconStyle}>{t('Download')}</span>
266	                </Button>
267	              </Tooltip>
268	            </ToolbarItem>
269	          </ToolbarGroup>
270	        </Toolbar>
271	
272	        {this.state.items.length > 0 && (
273	          <Tabs
274	            activeKey={this.state.mainTab}
275	            onSelect={(_, tab) => this.setState({ mainTab: String(tab) })}
276	            isFilled={true}
277	          >
278	            {(this.state.newIstioPage ? this.groupItems() : this.state.items).map(item => this.addResource(item))}
279	          </Tabs>
280	        )}
281	        {this.props.disableAction && (
282	          <div className={kialiStyle({ color: PFColors.Danger })}>
283	            {t('User does not have enough permission for this action.')}
284	          </div>
285	        )}
286	      </Modal>
287	    );
288	  }
289	}

